    // output dimensions (stride=1, padding=0, dilation=1)
    uint32_t OH = H - KH + 1;
    uint32_t OW = W - KW + 1;

    // Determine tile sizes to fit in UB
    // For each tile we need:
    // - input patch: C * (tileOH+KH-1) * (tileOW+KW-1) floats
    // - weight slice: tileK * C * KH * KW floats
    // - output tile: tileK * tileOH * tileOW floats
    // approximate budget: 3 * max(tileK*C*KH*KW, C*(tileOH+KH-1)*(tileOW+KW-1), tileK*tileOH*tileOW)

    uint32_t tileK = 16;   // output channels per tile
    uint32_t tileOH = 16;  // output height per tile
    uint32_t tileOW = 16;  // output width per tile

    // try to fit, adjust if needed
    uint32_t patchSize = C * (tileOH + KH - 1) * (tileOW + KW - 1);
    uint32_t weightSize = tileK * C * KH * KW;
    uint32_t outSize = tileK * tileOH * tileOW;
    uint32_t maxSize = (patchSize > weightSize ? patchSize : weightSize) > outSize ? (patchSize > weightSize ? patchSize : weightSize) : outSize;
    maxSize *= sizeof(float);
    if (maxSize > UB_BUDGET_BYTES) {
        // reduce tile sizes (simple shrink)
        while (maxSize > UB_BUDGET_BYTES && tileK > 1 && tileOH > 1 && tileOW > 1) {
            if (tileK > 8) tileK /= 2;
            else if (tileOH > 8) tileOH /= 2;
            else tileOW /= 2;
            patchSize = C * (tileOH + KH - 1) * (tileOW + KW - 1);
            weightSize = tileK * C * KH * KW;
            outSize = tileK * tileOH * tileOW;
            maxSize = (patchSize > weightSize ? patchSize : weightSize) > outSize ? (patchSize > weightSize ? patchSize : weightSize) : outSize;
            maxSize *= sizeof(float);
        }
    }

    uint32_t blockDim = 8;  // conservative, can increase based on output size
    uint32_t totalOutElems = N * K * OH * OW;
    (void)totalOutElems;

    context->SetBlockDim(blockDim);

    tiling.set_batch(N);
    tiling.set_inChannels(C);
    tiling.set_inHeight(H);
    tiling.set_inWidth(W);
    tiling.set_outChannels(K);
    tiling.set_outHeight(OH);
    tiling.set_outWidth(OW);
    tiling.set_kernelH(KH);
    tiling.set_kernelW(KW);
    tiling.set_tileOutChannels(tileK);
    tiling.set_tileOutHeight(tileOH);
    tiling.set_tileOutWidth(tileOW);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

